/** Inventory section — loaded from pre-built JSON */
function InventoryCard({ neighborhood }: { neighborhood: string }) {
  const [stats, setStats] = useState<NeighborhoodLeadStats | null>(null);
  const [loading, setLoading] = useState(true);
  const [notBuilt, setNotBuilt] = useState(false);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    setLoading(true);
    setStats(null);
    setError(null);
    setNotBuilt(false);

    fetchNeighborhoodLeadStats()
      .then((map) => {
        if (map.size === 0) {
          setNotBuilt(true);
          return;
        }
        const key = stripNeighborhoodName(neighborhood);
        const found = map.get(key) ?? null;
        setStats(found);
      })
      .catch((e) => setError(String(e)))
      .finally(() => setLoading(false));
  }, [neighborhood]);

  if (notBuilt) {
    return (
      <DataCard
        title="Service Line Inventory"
        loading={false}
        error={null}
        attribution={{ datasetName: 'GCWW Lead Service Line Inventory', lastUpdated: null }}
      >
        <div className="bg-amber-50 border border-amber-200 rounded-lg p-4 text-sm text-amber-900 space-y-2">
          <p className="font-semibold">⚙️ Pre-computed data not yet generated</p>
          <p>
            The full service line inventory requires a one-time build step. Run this command
            in the project directory to generate the data:
          </p>
          <pre className="bg-amber-100 rounded p-2 text-xs font-mono overflow-x-auto">
            python3 scripts/build_lead.py
          </pre>
          <p>
            Once generated, <code className="text-xs bg-amber-100 px-1 rounded">public/data/lead_service_lines.json</code> will
            populate this section with lead/unknown/copper counts for all 52 neighborhoods.
          </p>
          <p>
            In the meantime, the <strong>Replacement Activity</strong> card below shows live data
            from Cincinnati's open data portal.
          </p>
        </div>
      </DataCard>
    );
  }

  const leadOrUnknown = stats ? stats.lead + stats.unknown : 0;

  return (
    <DataCard
      title="Service Line Inventory"
      loading={loading}
      error={error}
      attribution={{ datasetName: 'GCWW Lead Service Line Inventory', lastUpdated: stats?.asOf ?? null }}
    >
      {stats === null && !loading ? (
        <p className="text-sm text-gray-500">No inventory data found for {neighborhood}.</p>
      ) : stats ? (
        <div className="space-y-2">
          {/* Risk badge */}
          <div className={`inline-flex items-center gap-2 px-3 py-1.5 rounded-full text-sm font-semibold mb-3 ${riskColor(leadOrUnknown, stats.total)}`}>
            <span>{riskLabel(leadOrUnknown, stats.total)}</span>
            <span className="font-normal opacity-75">·</span>
            <span>{pct(leadOrUnknown, stats.total)} of lines are lead or unknown</span>
          </div>

          {/* Breakdown */}
          <StatRow
            label="Lead service lines"
            value={stats.lead}
            barWidth={stats.total ? (stats.lead / stats.total) * 100 : 0}
            barColor="bg-red-500"
            note="Confirmed lead material — replacement is a priority"
          />
          <StatRow
            label="Unknown material"
            value={stats.unknown}
            barWidth={stats.total ? (stats.unknown / stats.total) * 100 : 0}
            barColor="bg-orange-400"
            note="Material unconfirmed — treated as potentially lead"
          />
          <StatRow
            label="Galvanized steel"
            value={stats.galvanized}
            barWidth={stats.total ? (stats.galvanized / stats.total) * 100 : 0}
            barColor="bg-yellow-400"
            note="Corrosion concern; may have been connected to a lead line"
          />
          <StatRow
            label="Copper or safe material"
            value={stats.copper}
            barWidth={stats.total ? (stats.copper / stats.total) * 100 : 0}
            barColor="bg-green-500"
            note="Confirmed non-lead material"
          />
          <StatRow
            label="Already replaced"
            value={stats.replaced}
            barWidth={stats.total ? (stats.replaced / stats.total) * 100 : 0}
            barColor="bg-blue-500"
            note="Private-side replacement completed through GCWW program"
          />
          <div className="pt-2 border-t border-gray-100 flex justify-between items-center">
            <span className="text-sm text-gray-500">Total service lines</span>
            <span className="text-sm font-bold text-[#1A4A6B]">{stats.total.toLocaleString()}</span>
          </div>
        </div>
      ) : null}
    </DataCard>
  );
}

/** Replacement Activity card — live SODA data from ntfu-vnkd */
function ReplacementActivityCard({ neighborhood }: { neighborhood: string }) {
  const [records, setRecords] = useState<LeadReplacementRecord[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    setLoading(true);
    setError(null);
    fetchLeadReplacements(neighborhood)
      .then(setRecords)
      .catch((e) => setError(String(e)))
      .finally(() => setLoading(false));
  }, [neighborhood]);

  // Group by year for chart
  const yearData = useMemo(() => {
    const counts: Record<string, number> = {};
    for (const r of records) {
      // Try to parse year from date_completed — field name unconfirmed until live test
      const raw = r.date_completed ?? '';
      const year = raw.slice(0, 4);
      if (/^\d{4}$/.test(year)) {
        counts[year] = (counts[year] ?? 0) + 1;
      }
    }
    return Object.entries(counts)
      .sort(([a], [b]) => a.localeCompare(b))
      .map(([year, count]) => ({ year, count }));
  }, [records]);

  const total = records.length;

  return (
    <DataCard
      title="Replacement Program Activity"
      loading={loading}
      error={error}
      attribution={{
        datasetName: 'GCWW Private-Side Lead Service Line Replacements',
        lastUpdated: null,
        uid: 'ntfu-vnkd',
      }}
    >
      {total === 0 && !loading ? (
        <div className="text-sm text-gray-500 space-y-1">
          <p>No replacement records found for {neighborhood}.</p>
          <p className="text-xs text-gray-400">
            This may mean the dataset has no records matching this neighborhood name, or that
            the live query returned an unexpected field format. Field names in this dataset
            have not yet been confirmed through live testing.
          </p>
        </div>
      ) : (
        <div className="space-y-4">
          <div className="bg-blue-50 rounded-lg px-4 py-3 flex items-center justify-between">
            <div>
              <div className="text-2xl font-bold text-[#1A4A6B]">{total.toLocaleString()}</div>
              <div className="text-sm text-gray-600">Private-side replacements recorded</div>
            </div>
            <div className="text-right text-xs text-gray-500">
              <p>This dataset records private-side</p>
              <p>replacements completed through</p>
              <p>GCWW's program</p>
            </div>
          </div>

          {yearData.length > 0 && (
            <div>
              <p className="text-xs text-gray-500 mb-2">Replacements by year</p>
              <ResponsiveContainer width="100%" height={140}>
                <BarChart data={yearData} margin={{ top: 4, right: 4, bottom: 4, left: 0 }}>
                  <XAxis dataKey="year" tick={{ fontSize: 11 }} />
                  <YAxis tick={{ fontSize: 11 }} width={30} />
                  <Tooltip
                    formatter={(v: number) => [v, 'Replacements']}
                    contentStyle={{ fontSize: '12px' }}
                  />
                  <Bar dataKey="count" fill="#1A4A6B" radius={[2, 2, 0, 0]}>
                    {yearData.map((_, i) => (
                      <Cell
                        key={i}
                        fill={i === yearData.length - 1 ? '#E95B2E' : '#1A4A6B'}
                      />
                    ))}
                  </Bar>
                </BarChart>
              </ResponsiveContainer>
              <p className="text-xs text-gray-400 mt-1">Most recent year highlighted in orange.</p>
            </div>
          )}

          <p className="text-xs text-gray-500">
            Note: "Private-side" means the pipe from the curb to your home. The city-side
            (main to curb) replacement is handled separately and is not in this dataset.
          </p>
        </div>
      )}
    </DataCard>
  );
}

