/** City-wide neighborhood comparison bar chart */
function CityWideComparisonCard() {
  const [allStats, setAllStats] = useState<NeighborhoodLeadStats[]>([]);
  const [loading, setLoading] = useState(true);
  const [notBuilt, setNotBuilt] = useState(false);

  useEffect(() => {
    fetchNeighborhoodLeadStats()
      .then((map) => {
        if (map.size === 0) {
          setNotBuilt(true);
          return;
        }
        const sorted = Array.from(map.values())
          .filter((s) => s.total > 0)
          .sort((a, b) => (b.lead + b.unknown) / b.total - (a.lead + a.unknown) / a.total);
        setAllStats(sorted);
      })
      .catch(() => setNotBuilt(true))
      .finally(() => setLoading(false));
  }, []);

  const chartData = useMemo(
    () =>
      allStats.map((s) => ({
        name: s.name.length > 14 ? s.name.slice(0, 13) + '…' : s.name,
        fullName: s.name,
        pct: Math.round(((s.lead + s.unknown) / s.total) * 100),
      })),
    [allStats]
  );

  if (notBuilt) return null; // Don't show the section if data isn't built yet

  return (
    <DataCard
      title="City-Wide Comparison — % Lead or Unknown Lines by Neighborhood"
      loading={loading}
      error={null}
      attribution={{ datasetName: 'GCWW Lead Service Line Inventory', lastUpdated: null }}
    >
      {chartData.length === 0 && !loading ? (
        <p className="text-sm text-gray-500">No city-wide comparison data available.</p>
      ) : (
        <div>
          <p className="text-xs text-gray-500 mb-3">
            Neighborhoods sorted by percentage of service lines that are confirmed lead or
            unknown material. Higher = more residents potentially at risk.
          </p>
          <div style={{ height: Math.max(300, chartData.length * 22) }}>
            <ResponsiveContainer width="100%" height="100%">
              <BarChart
                layout="vertical"
                data={chartData}
                margin={{ top: 0, right: 40, bottom: 0, left: 120 }}
              >
                <XAxis
                  type="number"
                  domain={[0, 100]}
                  tickFormatter={(v) => `${v}%`}
                  tick={{ fontSize: 11 }}
                />
                <YAxis
                  type="category"
                  dataKey="name"
                  tick={{ fontSize: 10 }}
                  width={115}
                />
                <Tooltip
                  formatter={(v: number, _name, props) => [
                    `${v}%`,
                    `Lead or unknown — ${props.payload?.fullName ?? ''}`,
                  ]}
                  contentStyle={{ fontSize: '12px' }}
                />
                <Bar dataKey="pct" radius={[0, 2, 2, 0]}>
                  {chartData.map((entry, i) => (
                    <Cell
                      key={i}
                      fill={
                        entry.pct > 50 ? '#B91C1C'
                        : entry.pct > 25 ? '#EA580C'
                        : entry.pct > 10 ? '#CA8A04'
                        : '#16A34A'
                      }
                    />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>
      )}
    </DataCard>
  );
}

